import csv
import re
from datetime import datetime

def normalize_date(date_str):
    """Normalize date string to ISO format"""
    date_str = date_str.strip()
    if re.match(r'\d{1,2}/\d{1,2}/\d{4}', date_str):
        # MM/DD/YYYY
        return datetime.strptime(date_str, '%m/%d/%Y').strftime('%Y-%m-%d')
    elif re.match(r'\d{4}-\d{2}-\d{2}', date_str):
        # YYYY-MM-DD
        return date_str
    elif re.match(r'\w+ \d+, \d{4}', date_str):
        # 'January 5, 2024'
        month_name, day, year = date_str.split()
        return datetime.strptime(f'{month_name} {day}, {year}', '%B %d, %Y').strftime('%Y-%m-%d')
    else:
        raise ValueError(f"Invalid date format: {date_str}")

def normalize_price(price_str):
    """Normalize price string to plain float"""
    price_str = price_str.strip()
    if price_str.startswith('$'):
        # '$1,234.56'
        return float(price_str[1:].replace(',', ''))
    elif re.match(r'\d+\.\d+', price_str):
        # '1234.56'
        return float(price_str)
    elif re.match(r'\d{1,3}(,\d{3})*\.\d{2}', price_str):
        # '1.234,56' (European)
        return float(price_str.replace(',', '.'))
    else:
        raise ValueError(f"Invalid price format: {price_str}")

def normalize_csv(csv_file):
    """Normalize messy CSV to ISO dates and plain floats"""
    with open(csv_file, 'r', encoding='utf-8', errors='ignore') as f:
        reader = csv.reader(f)
        with open(csv_file + '.normalized', 'w', newline='') as out_f:
            writer = csv.writer(out_f)
            for row in reader:
                normalized_row = []
                for cell in row:
                    try:
                        if re.match(r'\d{1,2}/\d{1,2}/\d{4}|^\d{4}-\d{2}-\d{2}|^\w+ \d+, \d{4}$', cell):
                            # Date
                            normalized_row.append(normalize_date(cell))
                        elif re.match(r'^\$|^\d+\.\d+|^\d{1,3}(,\d{3})*\.\d{2}$', cell):
                            # Price
                            normalized_row.append(normalize_price(cell))
                        else:
                            # Other fields
                            normalized_row.append(cell)
                    except ValueError as e:
                        print(f"Error normalizing cell: {e}")
                writer.writerow(normalized_row)

if __name__ == '__main__':
    normalize_csv('messy.csv')
```
